from vex import VexClient

vex = VexClient(api_key='your-vex-key')
policy_id = 'cs-support-high-risk'

@vex.guardrail(policy_id)
def vex_tool_call(event):
    return vex.verify_tool_call(event.tool_name, event.args)

@vex.guardrail(policy_id)
def vex_memory_check(event):
    return vex.check_memory_growth(event.memory, max_tokens=50000)

agent.add_event_listener('tool_call', vex_tool_call)
agent.add_event_listener('memory_update', vex_memory_check)

@vex.guardrail(policy_id, verifications=['pii_filtering', 'response_accuracy'])
def vex_llm_output(event):
    verified = vex.verify({
        'output': event.output,
        'query': event.query,
        'entities': vex.extract_pii(event.output)
    })
    if not verified:
        return 'Response blocked: PII detected'
    return event.output

agent.add_event_listener('llm_output', vex_llm_output)

@vex.guardrail(policy_id, verifications=['tone_consistency', 'policy_compliance'])
def vex_final_response(event):
    checks = vex.verify({
        'response': event.response,
        'tone_target': 'professional',
        'policies': ['no_personal_opinions', 'escalate_abuse']
    })
    if checks.escalation_triggered:
        agent.tools['escalate']({'reason': checks.violation})
    return checks.approved_response

agent.add_event_listener('response_generated', vex_final_response)
